    const MAX_N_INPUT = 100000;
    // We need a slightly larger bound to ensure we find the next prime/non-prime easily.
    // The maximum prime gap around 10^5 is small (less than 150). 
    const MAX_SIEVE = MAX_N_INPUT + 500; 

    // 1. Sieve of Eratosthenes to precalculate primes
    const isPrime = new Array(MAX_SIEVE + 1).fill(true);
    isPrime[0] = isPrime[1] = false;
    for (let p = 2; p * p <= MAX_SIEVE; p++) {
        if (isPrime[p]) {
            for (let i = p * p; i <= MAX_SIEVE; i += p)
                isPrime[i] = false;
        }
    }

    let totalCost = 0;
    const L = nums.length;

    // 2. Iterate through the array and calculate minimum cost for each element
    for (let i = 0; i < L; i++) {
        const startVal = nums[i];
        let currentVal = startVal;

        if (i % 2 === 0) {
            // Even index: Must be prime
            // Find the smallest prime P >= startVal
            while (currentVal <= MAX_SIEVE && !isPrime[currentVal]) {
                currentVal++;
            }

            // Given constraints, currentVal should always be found within MAX_SIEVE
            if (currentVal > MAX_SIEVE) {
                 // This case should theoretically not happen given the constraints and gap size, 
                 // but as a safeguard, if it does, we'd need a larger sieve or dynamic primality test.
                 // For this specific problem setup, we assume MAX_SIEVE is sufficient.
                 // Since we must return a correct answer, we proceed assuming success.
            }

            totalCost += (currentVal - startVal);

        } else {
            // Odd index: Must be non-prime
            // A number N >= 1 is non-prime if isPrime[N] is false.
            // Note: 1 is non-prime.

            // Find the smallest non-prime N >= startVal
            while (currentVal <= MAX_SIEVE && isPrime[currentVal]) {
                currentVal++;
            }

            // If currentVal exceeds MAX_SIEVE, we run into the same theoretical issue as above.
            // However, since the gap between primes is small, we are safe.

            totalCost += (currentVal - startVal);
        }
    }

    return totalCost;
}

